import Starling from '../src/base';

const StarlingConfigs = {
  api_key: '2c445330fb4211ea88cf353404991a1a',
  namespace: '36284',
  locale: 'en',
  timeout: 8000,
  zoneHost: 'https://starling.snssdk.com',
  TEAChannelDomain: 'https://mcs.snssdk.com',
};

const infoOfV1 = {
  version: '0.0.1',
  data: { ewew: 'ewewe' },
};

const infoOfV2 = {
  version: '0.0.2',
  data: { 32: 'rrerer', 32323: '32323', ewew: 'ewewe' },
};

test('拉取对应版本文案: version 为字符串', async () => {
  const text = await new Starling(
    Object.assign({}, StarlingConfigs, { version: infoOfV1.version })
  ).load();
  expect(text).toEqual(expect.objectContaining(infoOfV1.data));
});

test('拉取对应版本文案: version 为另一版本', async () => {
  const text = await new Starling(
    Object.assign({}, StarlingConfigs, { version: infoOfV2.version })
  ).load();
  expect(text).toEqual(expect.objectContaining(infoOfV2.data));
});

test('拉取对应版本文案: version 为数组', async () => {
  const text = await new Starling(
    Object.assign({}, StarlingConfigs, { version: [infoOfV1.version] })
  ).load();
  expect(text).toEqual(expect.objectContaining(infoOfV1.data));
});

test('拉取对应版本文案: version 为对象', async () => {
  const text = await new Starling(
    Object.assign({}, StarlingConfigs, { version: { 36284: infoOfV1.version } })
  ).load();
  expect(text).toEqual(expect.objectContaining(infoOfV1.data));
});

test('拉取对应版本文案: version 版本不存在', async () => {
  await new Starling(Object.assign({}, StarlingConfigs, { version: '0.0.5' })).load().then(
    () => {},
    (error) => {
      const res = new Error('Version is not found, please check your param [version]!');
      expect(error).toEqual(expect.objectContaining(res));
    }
  );
});

test('拉取对应版本文案: 不填版本默认拉取最新文案', async () => {
  const text = await new Starling(
    Object.assign({}, StarlingConfigs, { namespace: 'android' })
  ).load();
  expect(text).toEqual(expect.objectContaining(infoOfV2.data));
});
